mapper.select:
		/** CmmtMenuRoleDao.selectByMenuId */
        SELECT system_id
            ,menu_id
            ,role_id
            ,creator_id
            ,created_dt
        from cmmt_menu_role
		where
			system_id = #{systemId}
			and menu_id = #{menuId}

mapper.delete:
/** CmmtMenuRoleDao.deleteByRoleId */
delete from cmmt_menu_role
where
	system_id = #{systemId}
	and role_id = #{roleId}

mapper.insert:
/** CmmtMenuRoleDao.insert */
insert into cmmt_menu_role (
	system_id
	,menu_id
	,role_id
	,creator_id
	,created_dt
) values (
	#{systemId}
	,#{menuId}
	,#{roleId}
	,#{creatorId}
	,#{createdDt}
)

/** CmmtMenuRoleDao.insertList */
insert into cmmt_menu_role (
	system_id
	,menu_id
	,role_id
	,creator_id
	,created_dt
) values

	(
		#{item.systemId}
		,#{item.menuId}
		,#{item.roleId}
		,#{item.creatorId}
		,#{item.createdDt}
	)
